<template>
  <div>
    <p><strong>Dym:</strong> {{ smokeLevel }}</p>
  </div>
</template>

<script>
export default {
  name: 'SmokeSensor',
  data() {
    return {
      smokeLevel: 'Brak danych'
    };
  },
  mounted() {
    this.fetchData();
    setInterval(this.fetchData, 5000);
  },
  methods: {
    fetchData() {
      fetch('/get-data')
        .then(response => response.json())
        .then(data => {
          this.smokeLevel = data.smoke;
        })
        .catch(error => {
          console.error('Error:', error);
          this.smokeLevel = 'Błąd odczytu danych';
        });
    }
  }
}
</script>